agent_output:
{
  "executive_summary": "A real-time courier bidding system built around Redis atomic operations for race-free job acceptance, WebSocket fan-out for sub-second courier notifications, and a timer-driven Bid Window Manager for the 15-second lifecycle. The architecture ensures exactly-once assignment through a Redis Lua script (compare-and-set), handles 500 concurrent bid windows comfortably within Redis's throughput ceiling, and degrades gracefully under load via zone-based partitioning of both WebSocket connections and bid state.",

  "architecture": {
    "components": [
      {
        "name": "Order Ingestion Service",
        "responsibility": "Receives new orders from the marketplace API, validates them, persists the order, and emits an OrderPlaced domain event to kick off the bidding lifecycle.",
        "boundaries": "Owns order creation and validation only. Does not know about couriers or bidding logic. Publishes events; never calls downstream services synchronously."
      },
      {
        "name": "Courier Eligibility Service",
        "responsibility": "Given an order's pickup zone and requirements (vehicle type, payload weight), returns the set of eligible, on-duty couriers. Maintains courier availability state (on-duty, in-delivery, offline) and zone membership.",
        "boundaries": "Read-heavy query service. Owns courier availability projections. Does not mutate courier profiles — consumes availability events from the Courier App Gateway."
      },
      {
        "name": "Bid Window Manager",
        "responsibility": "Orchestrates the 15-second bid window lifecycle: (1) creates a bid window in Redis on OrderPlaced, (2) requests eligible couriers, (3) triggers fan-out via the Courier Gateway, (4) schedules the 15-second timeout, (5) on timeout with no winner, invokes auto-assignment to highest-rated eligible courier.",
        "boundaries": "Owns the bid window state machine (OPEN → CLAIMED | EXPIRED → ASSIGNED). Stateless process — all state lives in Redis. Multiple instances can run concurrently since Redis provides the coordination."
      },
      {
        "name": "Bid Processor",
        "responsibility": "Handles courier acceptance attempts. Executes an atomic Redis Lua script to determine if this courier is the first to accept. Returns win/lose result to the courier within milliseconds. On win, publishes BidWon event; on lose, returns immediate rejection.",
        "boundaries": "Extremely narrow: accepts a (orderId, courierId) tuple, executes the atomic claim, returns result. No business logic beyond the atomic check and basic eligibility validation."
      },
      {
        "name": "Courier App Gateway (WebSocket)",
        "responsibility": "Maintains persistent WebSocket connections with courier mobile apps. Handles: (a) pushing new job notifications to eligible couriers, (b) receiving acceptance messages from couriers and forwarding to Bid Processor, (c) pushing bid-result notifications (won/lost/expired). Also tracks courier online/offline state.",
        "boundaries": "Transport layer only — no business logic. Partitioned by zone for horizontal scaling. Each gateway instance manages connections for couriers in a subset of zones."
      },
      {
        "name": "Assignment Service",
        "responsibility": "Finalizes courier-to-order assignment after a bid is won or auto-assigned. Persists the assignment, updates courier status to in-delivery, notifies the order service, and triggers downstream logistics (routing, ETA calculation).",
        "boundaries": "Downstream of bidding. Consumes BidWon and AutoAssigned events. Owns the assignment aggregate."
      },
      {
        "name": "Redis Cluster (Bid State Store)",
        "responsibility": "Holds all transient bid window state: bid window status, winner slot, eligible courier sets, and the delayed expiry queue. Provides atomic operations via Lua scripts. All bid state has TTLs — no long-term persistence needed.",
        "boundaries": "Infrastructure component. Accessed only by Bid Window Manager and Bid Processor. Not used for durable order or courier data."
      },
      {
        "name": "Timeout Scheduler",
        "responsibility": "Polls a Redis sorted set (score = expiry timestamp) to detect bid windows that have reached their 15-second deadline without a winner. Triggers auto-assignment flow for expired windows.",
        "boundaries": "Lightweight polling loop. Multiple instances can run safely — uses Redis atomic ZPOPMIN to prevent double-processing of the same expired window."
      }
    ],
    "interfaces": [
      {
        "from": "Order Ingestion Service",
        "to": "Bid Window Manager",
        "contract": "Domain event: OrderPlaced { orderId, pickupZone, pickupLocation, deliveryLocation, requirements, timestamp }. Published via message broker (Redis Streams or NATS).",
        "coupling_type": "event (async, loose)"
      },
      {
        "from": "Bid Window Manager",
        "to": "Courier Eligibility Service",
        "contract": "Sync query: GET /eligible-couriers?zone={zone}&vehicleType={type}&maxWeight={kg} → { couriers: [{ courierId, rating, location }] }",
        "coupling_type": "request-response (sync, moderate)"
      },
      {
        "from": "Bid Window Manager",
        "to": "Redis Cluster",
        "contract": "Creates bid window: HSET bid:{orderId} status OPEN eligible [courierIds] createdAt {ts}; ZADD bid:expiry {ts+15} {orderId}; SET bid:{orderId}:winner (empty, awaiting claim)",
        "coupling_type": "data store (direct)"
      },
      {
        "from": "Bid Window Manager",
        "to": "Courier App Gateway",
        "contract": "Internal command: FanOutJobNotification { orderId, courierIds[], jobDetails }. Sent via internal pub/sub channel keyed by zone.",
        "coupling_type": "command (async, loose)"
      },
      {
        "from": "Courier App Gateway",
        "to": "Bid Processor",
        "contract": "Sync RPC: POST /bids/accept { orderId, courierId } → { result: 'won' | 'lost' | 'expired' }. Must respond in <50ms p99.",
        "coupling_type": "request-response (sync, tight — latency critical)"
      },
      {
        "from": "Bid Processor",
        "to": "Redis Cluster",
        "contract": "Lua script execution: atomic SET-if-not-exists on bid:{orderId}:winner with courierId. Returns 1 (won) or 0 (lost).",
        "coupling_type": "data store (direct)"
      },
      {
        "from": "Bid Processor",
        "to": "Courier App Gateway",
        "contract": "Event: BidWon { orderId, winnerId } — triggers push to winner ('You got the job') and losers ('Job taken').",
        "coupling_type": "event (async, loose)"
      },
      {
        "from": "Timeout Scheduler",
        "to": "Redis Cluster",
        "contract": "ZPOPMIN bid:expiry — atomically pops expired bid windows. Then reads eligible couriers and their ratings to determine auto-assignment target.",
        "coupling_type": "data store (direct)"
      },
      {
        "from": "Timeout Scheduler",
        "to": "Assignment Service",
        "contract": "Event: AutoAssigned { orderId, courierId, reason: 'timeout_highest_rated' }",
        "coupling_type": "event (async, loose)"
      },
      {
        "from": "Bid Processor",
        "to": "Assignment Service",
        "contract": "Event: BidWon { orderId, courierId, acceptedAt }",
        "coupling_type": "event (async, loose)"
      }
    ],
    "data_flow": "1) Order Ingestion publishes OrderPlaced event → 2) Bid Window Manager consumes it, queries Courier Eligibility for eligible couriers (~30), writes bid window state to Redis (status=OPEN, eligible set, expiry score), and sends FanOutJobNotification to Courier Gateway → 3) Gateway pushes job to all eligible couriers' WebSocket connections simultaneously → 4) Couriers see the job on their app; first to tap 'Accept' sends acceptance via WebSocket → 5) Gateway forwards to Bid Processor, which executes atomic Redis Lua script: if bid:{orderId}:winner is unset, sets it to this courierId and returns 'won'; otherwise returns 'lost' → 6) Bid Processor publishes BidWon event → Gateway notifies winner and all losers; Assignment Service finalizes the pairing → 7) IF no courier accepts within 15s, Timeout Scheduler pops the expired bid window from the sorted set, selects highest-rated eligible courier, publishes AutoAssigned event → Assignment Service finalizes → Gateway notifies the auto-assigned courier.",
    "patterns_used": [
      {
        "pattern": "Atomic Compare-and-Set via Redis Lua Script",
        "rationale": "The core invariant — exactly one courier wins a job — requires an atomic, serialized operation. A Redis Lua script executes atomically on a single thread, making it impossible for two couriers to both 'win'. This is simpler and faster than distributed locks or database-level optimistic concurrency, and Redis single-thread model guarantees serialization without explicit locking."
      },
      {
        "pattern": "WebSocket Fan-Out with Zone Partitioning",
        "rationale": "Couriers need sub-second notification of new jobs and bid results. HTTP polling would add unacceptable latency and waste bandwidth. WebSockets provide persistent bidirectional channels. Zone-based partitioning of gateway instances ensures horizontal scalability — each gateway only manages connections for its zone's couriers, keeping fan-out bounded to ~30 per job."
      },
      {
        "pattern": "Delayed Queue (Redis Sorted Set) for Timeout",
        "rationale": "The 15-second timeout must fire reliably even if the originating Bid Window Manager instance dies. A Redis sorted set with timestamp scores and ZPOPMIN-based polling provides distributed, crash-tolerant, at-most-once timer processing without requiring an external scheduler like cron."
      },
      {
        "pattern": "Event-Driven Architecture with Domain Events",
        "rationale": "Decouples the bid lifecycle from order management and assignment finalization. The Order Ingestion Service doesn't need to know about bidding mechanics; the Assignment Service doesn't need to know about WebSockets. Events allow independent scaling and evolution of each component."
      },
      {
        "pattern": "Stateless Processing with External State Store",
        "rationale": "Bid Window Manager and Bid Processor are stateless — all state lives in Redis. This allows horizontal scaling by adding instances, and any instance can handle any bid window. Crash recovery is trivial since no in-process state is lost."
      },
      {
        "pattern": "CQRS-lite for Courier Availability",
        "rationale": "Courier Eligibility Service maintains a read-optimized projection of courier availability, updated from events (courier goes online, starts delivery, completes delivery). This separates the write path (courier state changes) from the read path (eligibility queries during bid window creation), allowing the eligibility query to be fast and cache-friendly."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Bidding",
        "classification": "core",
        "aggregates": [
          {
            "name": "BidWindow",
            "root": "BidWindow",
            "invariants": [
              "A bid window can have at most one winner",
              "A bid window transitions OPEN → CLAIMED (courier accepted) or OPEN → EXPIRED (timeout) — never backward",
              "Only eligible couriers can participate in a bid window",
              "A bid window has a fixed 15-second TTL from creation"
            ],
            "entities": ["BidWindow"],
            "value_objects": ["BidWindowId", "BidStatus", "TimeoutPolicy", "EligibleCourierSet"]
          }
        ]
      },
      {
        "name": "Order Management",
        "classification": "supporting",
        "aggregates": [
          {
            "name": "Order",
            "root": "Order",
            "invariants": [
              "An order must have a valid pickup and delivery location",
              "An order transitions through: PLACED → BIDDING → ASSIGNED → IN_TRANSIT → DELIVERED"
            ],
            "entities": ["Order"],
            "value_objects": ["OrderId", "Location", "OrderStatus", "DeliveryRequirements"]
          }
        ]
      },
      {
        "name": "Courier Management",
        "classification": "supporting",
        "aggregates": [
          {
            "name": "Courier",
            "root": "Courier",
            "invariants": [
              "A courier can only be assigned one active delivery at a time",
              "A courier must be on-duty to receive bid notifications",
              "Courier rating is derived from completed delivery history"
            ],
            "entities": ["Courier"],
            "value_objects": ["CourierId", "CourierRating", "Zone", "VehicleType", "AvailabilityStatus"]
          }
        ]
      },
      {
        "name": "Assignment",
        "classification": "supporting",
        "aggregates": [
          {
            "name": "Assignment",
            "root": "Assignment",
            "invariants": [
              "An assignment links exactly one order to exactly one courier",
              "An assignment is immutable once created (reassignment creates a new aggregate)"
            ],
            "entities": ["Assignment"],
            "value_objects": ["AssignmentId", "AssignmentMethod"]
          }
        ]
      }
    ],
    "context_map": [
      {
        "upstream": "Order Management",
        "downstream": "Bidding",
        "relationship": "Customer-Supplier — Order Management publishes OrderPlaced; Bidding consumes it. Bidding has no influence over the Order model but depends on its events."
      },
      {
        "upstream": "Courier Management",
        "downstream": "Bidding",
        "relationship": "Conformist — Bidding uses courier IDs, ratings, and zone data as-is from Courier Management. An Anti-Corruption Layer translates courier data into the Bidding context's EligibleCourierSet value object."
      },
      {
        "upstream": "Bidding",
        "downstream": "Assignment",
        "relationship": "Customer-Supplier — Bidding publishes BidWon and AutoAssigned events; Assignment consumes them to finalize the courier-order pairing."
      },
      {
        "upstream": "Bidding",
        "downstream": "Order Management",
        "relationship": "Customer-Supplier — Bidding publishes BidWon/AutoAssigned; Order Management updates order status to ASSIGNED."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Redis as the sole bid state store (not a relational database)",
      "gains": "Sub-millisecond atomic operations, trivial implementation of the compare-and-set pattern via Lua scripts, built-in TTL for automatic cleanup, sorted sets for timeout scheduling. At 500 concurrent windows × 30 couriers, Redis handles this without breaking a sweat.",
      "sacrifices": "Redis is not durable by default — a crash could lose in-flight bid windows. Bid state is ephemeral (15-second lifecycle), so this is acceptable. For auditability, bid results are published as events and persisted downstream.",
      "alternatives_considered": [
        "PostgreSQL with SELECT FOR UPDATE — provides durability but adds 5-10ms per lock acquisition, unacceptable for real-time bidding",
        "DynamoDB conditional writes — viable but higher latency (~10ms) and more complex failure modes than Redis Lua",
        "Application-level distributed lock (Redlock) — unnecessary complexity; single Redis Lua script is sufficient since bid state is not cross-shard"
      ]
    },
    {
      "decision": "WebSocket for courier communication (not HTTP polling or server-sent events)",
      "gains": "Bidirectional communication: push job notifications AND receive acceptances on the same connection. Sub-100ms delivery latency. Natural fit for mobile apps that need real-time updates.",
      "sacrifices": "Operational complexity: sticky sessions or connection-aware load balancing required. Mobile network transitions (WiFi→cellular) cause reconnection churn. Must handle ungraceful disconnects.",
      "alternatives_considered": [
        "HTTP long polling — simpler infrastructure but adds 1-3 seconds of latency per notification cycle, eating into the 15-second window",
        "Server-Sent Events (SSE) — server-to-client only; would still need a separate HTTP endpoint for acceptance, adding complexity",
        "Push notifications (APNs/FCM) — too slow (1-5 seconds delivery) and unreliable for a 15-second window"
      ]
    },
    {
      "decision": "Auto-assign to highest-rated courier on timeout (not re-broadcast or cancel)",
      "gains": "Guarantees every order gets assigned — no order left unmatched. Predictable fallback behavior. Highest-rated courier selection rewards reliable couriers.",
      "sacrifices": "Forces an assignment on a courier who didn't actively accept, which could lead to poor service if the courier is actually busy but didn't update status. Mitigated by requiring couriers to be marked on-duty.",
      "alternatives_considered": [
        "Re-broadcast to a wider zone — adds latency (another 15-second window) and risks cascade failure under load",
        "Cancel and refund — unacceptable customer experience for a delivery marketplace",
        "Assign to closest courier — proximity doesn't correlate with reliability; rating is a better signal"
      ]
    },
    {
      "decision": "Zone-based partitioning of WebSocket gateway instances",
      "gains": "Bounded fan-out per gateway instance. Natural horizontal scaling — add gateway instances per zone as courier density grows. Failure isolation — a gateway crash only affects one zone.",
      "sacrifices": "Cross-zone jobs (pickup in zone A, courier in zone B) require multi-zone fan-out coordination. Mitigated by making eligibility zone-aware and allowing a job to target multiple gateway instances.",
      "alternatives_considered": [
        "Single monolithic WebSocket server — simpler but single point of failure and doesn't scale past ~50K connections",
        "Consistent-hash-based partitioning by courierId — more even distribution but loses the locality benefit of zone-based grouping"
      ]
    }
  ],

  "flexibility_points": [
    {
      "area": "Bid window duration",
      "evolution_path": "The 15-second timeout is a configuration value in the BidWindow aggregate, not a hardcoded constant. Can evolve to dynamic timeouts based on zone density, time of day, or order urgency without architectural changes."
    },
    {
      "area": "Courier scoring and auto-assignment strategy",
      "evolution_path": "Currently highest-rated courier wins auto-assignment. The strategy is a pluggable function: can evolve to factor in proximity, acceptance rate, current workload, or a composite score. Encapsulated behind a CourierRankingStrategy interface."
    },
    {
      "area": "Bidding model (first-accept vs competitive bidding)",
      "evolution_path": "Current model is first-to-accept wins. The atomic claim mechanism can evolve to collect all bids during the window and select the best one, by changing the Lua script from SET-if-not-exists to ZADD (collecting bids in a sorted set) and adding a selection step at timeout. The WebSocket and lifecycle infrastructure remains unchanged."
    },
    {
      "area": "Notification channels",
      "evolution_path": "WebSocket is the primary channel. The fan-out interface is abstracted — can add push notification fallback for couriers with unstable connections without modifying the Bid Window Manager."
    },
    {
      "area": "Eligibility criteria",
      "evolution_path": "Currently zone + vehicle type. The Courier Eligibility Service can incorporate new dimensions (certifications, customer preferences, courier blacklists) by extending its query model. Bidding context is insulated via the EligibleCourierSet value object."
    }
  ],

  "rigidity_points": [
    {
      "area": "Exactly-once assignment invariant",
      "reason": "The atomic Redis Lua script for bid claiming MUST remain the single source of truth for who won a bid. Any bypass or dual-write pattern would violate the core business invariant. This is intentional rigidity — the most critical invariant in the system."
    },
    {
      "area": "Redis as bid state store",
      "reason": "The entire real-time bidding path depends on Redis's single-threaded atomicity guarantees. Swapping Redis for another store requires re-validating the atomicity model. This coupling is acceptable because the bid state is ephemeral (15s TTL) and Redis is operationally well-understood."
    },
    {
      "area": "WebSocket as real-time transport",
      "reason": "The 15-second window demands sub-second notification latency. Any transport change must meet this SLA. WebSocket is deeply integrated into the Courier Gateway. Changing it would require rebuilding the gateway layer."
    },
    {
      "area": "Bid window state machine transitions",
      "reason": "OPEN → CLAIMED and OPEN → EXPIRED are the only valid transitions. Adding intermediate states (e.g., PENDING_CONFIRMATION) would require changes to the Lua script, timeout scheduler, and gateway notification logic. Intentionally kept minimal."
    }
  ],

  "risks": [
    {
      "risk": "Redis single point of failure — if Redis goes down, all active bid windows are lost and no new bids can be processed",
      "severity": "critical",
      "mitigation": "Deploy Redis in Sentinel or Cluster mode with automatic failover. Bid state is ephemeral (15s) so a failover window of 1-2 seconds loses at most a handful of in-flight bids. Add a circuit breaker that queues orders for rebidding if Redis is unavailable."
    },
    {
      "risk": "WebSocket disconnection during bid window — courier loses connection and misses the job, or accepts but the ACK is lost",
      "severity": "high",
      "mitigation": "Implement client-side reconnection with exponential backoff. On reconnect, the courier app queries for any active bid windows it's eligible for. For acceptance ACK loss: the Bid Processor returns the result synchronously, and if the WebSocket drops mid-response, the courier app retries the acceptance call (idempotent since Redis Lua script returns the same result on re-execution)."
    },
    {
      "risk": "Clock skew between Timeout Scheduler instances causes premature or late expiry of bid windows",
      "severity": "medium",
      "mitigation": "Use Redis server time (TIME command) for all timestamp calculations, not local system clocks. The sorted set scores are set by the Bid Window Manager using Redis server time + 15 seconds."
    },
    {
      "risk": "Courier marked on-duty but actually unavailable — auto-assignment forces a job on a courier who can't fulfill it",
      "severity": "high",
      "mitigation": "After auto-assignment, give the assigned courier 60 seconds to confirm. If they don't confirm, re-enter the bidding cycle. Track no-response rates and auto-flag couriers with high no-response for status verification."
    },
    {
      "risk": "Hot zone — a popular pickup zone generates many simultaneous bid windows, all targeting the same 30 couriers",
      "severity": "medium",
      "mitigation": "Rate-limit bid window creation per zone. If more than N bid windows are active for the same zone, queue excess orders with a short backoff. Also implement courier capacity tracking — once a courier has an active bid window they've accepted, exclude them from new windows."
    },
    {
      "risk": "Thundering herd on bid window expiry — if many bid windows expire simultaneously, the Timeout Scheduler and auto-assignment path could spike",
      "severity": "low",
      "mitigation": "ZPOPMIN with a batch size limit (e.g., 10 at a time) rate-limits expiry processing. Multiple Timeout Scheduler instances compete atomically for expired windows, spreading load."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Implement in three phases. Phase 1 (core path): Redis Lua script for atomic bid claiming, Bid Window Manager lifecycle, and basic HTTP-based acceptance endpoint — prove the atomicity invariant works. Phase 2 (real-time): Add WebSocket gateway with zone partitioning, replace HTTP acceptance with WebSocket-based acceptance, add fan-out notifications. Phase 3 (resilience): Add Timeout Scheduler with sorted-set polling, Redis Sentinel failover, reconnection handling, circuit breakers, and monitoring dashboards for bid window metrics (acceptance rate, timeout rate, average time-to-accept).",
    "files_to_create_or_modify": [
      "src/bidding/domain/BidWindow.ts — Aggregate root with state machine (OPEN/CLAIMED/EXPIRED), winner slot, eligible courier set",
      "src/bidding/domain/events.ts — BidWindowOpened, BidClaimed, BidWindowExpired, AutoAssigned domain events",
      "src/bidding/infrastructure/redis/bid-claim.lua — Atomic Lua script: check bid status is OPEN, check courier is eligible, SET winner if unset, return result",
      "src/bidding/infrastructure/redis/BidWindowRepository.ts — Redis-backed repository: create window, claim bid (via Lua), read state, manage TTLs",
      "src/bidding/application/BidWindowManager.ts — Orchestrator: handles OrderPlaced, creates bid window, triggers fan-out, handles timeout",
      "src/bidding/application/BidProcessor.ts — Thin service: validates input, delegates to repository.claim(), publishes result events",
      "src/gateway/CourierWebSocketGateway.ts — WebSocket server partitioned by zone, manages connections, handles fan-out and acceptance forwarding",
      "src/gateway/ConnectionRegistry.ts — Maps courierId → WebSocket connection, supports zone-based lookup for fan-out",
      "src/scheduler/TimeoutScheduler.ts — Polls Redis sorted set for expired bid windows, triggers auto-assignment",
      "src/eligibility/CourierEligibilityService.ts — Query service: returns eligible couriers for a zone with ratings",
      "src/assignment/AssignmentService.ts — Consumes BidClaimed/AutoAssigned events, persists assignment, updates order and courier state",
      "infrastructure/redis/docker-compose.yml — Redis Sentinel setup for local development",
      "tests/bidding/bid-claim-atomicity.test.ts — Concurrent acceptance test: spawn 30 parallel claim attempts, verify exactly 1 winner"
    ],
    "patterns_to_follow": "Use the aggregate pattern for BidWindow — all state transitions go through the aggregate root. Use domain events for cross-context communication. Use the repository pattern to abstract Redis operations behind a clean interface. The Lua script is an infrastructure detail hidden behind the repository. Use dependency injection throughout for testability. For the WebSocket gateway, use the adapter pattern to decouple transport from business logic.",
    "pitfalls_to_avoid": [
      "DO NOT use application-level locks (mutexes, semaphores) for bid claiming — they don't work across multiple server instances. The Redis Lua script IS the lock.",
      "DO NOT store bid window state in application memory — it must be in Redis for crash recovery and multi-instance consistency.",
      "DO NOT use Redis WATCH/MULTI/EXEC for the atomic claim — Lua scripts are simpler and more reliable for this use case since WATCH can fail under high contention.",
      "DO NOT fan out notifications synchronously in the bid window creation path — use async pub/sub to avoid blocking the bid window manager.",
      "DO NOT rely on Redis key expiry events (keyspace notifications) as the primary timeout mechanism — they are not guaranteed to fire exactly on time. Use sorted set polling instead.",
      "DO NOT allow a courier to participate in multiple active bid windows simultaneously without explicit handling — they could win two jobs at once. Track active bids per courier."
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 88,
    "high_confidence_areas": [
      "Atomic bid claiming via Redis Lua script — this is a well-proven pattern for exactly-once semantics",
      "WebSocket for real-time courier communication — standard approach for mobile real-time apps",
      "Event-driven decoupling between Order, Bidding, and Assignment contexts",
      "Scale math: 500 windows × 30 couriers = 15,000 ops is trivial for Redis and modest for WebSocket infrastructure"
    ],
    "low_confidence_areas": [
      "Auto-assignment UX: forcing a job on a courier who didn't actively accept has unclear real-world acceptance rates — may need a confirmation step",
      "Zone partitioning strategy: optimal zone granularity depends on geographic data and courier density patterns not provided",
      "Mobile network reliability: real-world WebSocket stability on cellular networks may require more aggressive reconnection and fallback strategies than outlined"
    ],
    "assumptions": [
      "A single Redis instance (or primary in Sentinel) can handle the bid claiming load — at 500 concurrent windows this is well within Redis capacity (100K+ ops/sec)",
      "Courier mobile apps can maintain stable WebSocket connections for the duration of their shift",
      "30 couriers per zone is an average — the system should handle zones with up to 200 couriers without architectural changes",
      "Order placement rate doesn't exceed the 500 concurrent bid window target by more than 2x during peak",
      "The marketplace has existing courier profile and order management systems — this design covers only the bidding subsystem"
    ]
  }
}

