{
  "executive_summary": "A real-time courier bidding system built around Redis atomic operations for race-free job acceptance, WebSocket fan-out for sub-second courier notifications, and a timer-driven Bid Window Manager for the 15-second lifecycle. The architecture ensures exactly-once assignment through a Redis Lua script (compare-and-set), handles 500 concurrent bid windows comfortably within Redis's throughput ceiling, and degrades gracefully under load via zone-based partitioning of both WebSocket connections and bid state.",

  "architecture": {
    "components": [
      {
        "name": "Order Ingestion Service",
        "responsibility": "Receives new orders from the marketplace API, validates them, persists the order, and emits an OrderPlaced domain event to kick off the bidding lifecycle.",
        "boundaries": "Owns order creation and validation only. Does not know about couriers or bidding logic. Publishes events; never calls downstream services synchronously."
      },
      {
        "name": "Courier Eligibility Service",
        "responsibility": "Given an order's pickup zone and requirements (vehicle type, payload weight), returns the set of eligible, on-duty couriers. Maintains courier availability state (on-duty, in-delivery, offline) and zone membership.",
        "boundaries": "Read-heavy query service. Owns courier availability projections. Does not mutate courier profiles — consumes availability events from the Courier App Gateway."
      },
      {
        "name": "Bid Window Manager",
