  "trade_offs": [
    {
      "decision": "Redis as the sole bid state store (not a relational database)",
      "gains": "Sub-millisecond atomic operations, trivial implementation of the compare-and-set pattern via Lua scripts, built-in TTL for automatic cleanup, sorted sets for timeout scheduling. At 500 concurrent windows × 30 couriers, Redis handles this without breaking a sweat.",
      "sacrifices": "Redis is not durable by default — a crash could lose in-flight bid windows. Bid state is ephemeral (15-second lifecycle), so this is acceptable. For auditability, bid results are published as events and persisted downstream.",
      "alternatives_considered": [
        "PostgreSQL with SELECT FOR UPDATE — provides durability but adds 5-10ms per lock acquisition, unacceptable for real-time bidding",
        "DynamoDB conditional writes — viable but higher latency (~10ms) and more complex failure modes than Redis Lua",
        "Application-level distributed lock (Redlock) — unnecessary complexity; single Redis Lua script is sufficient since bid state is not cross-shard"
      ]
    },
    {
      "decision": "WebSocket for courier communication (not HTTP polling or server-sent events)",
      "gains": "Bidirectional communication: push job notifications AND receive acceptances on the same connection. Sub-100ms delivery latency. Natural fit for mobile apps that need real-time updates.",
      "sacrifices": "Operational complexity: sticky sessions or connection-aware load balancing required. Mobile network transitions (WiFi→cellular) cause reconnection churn. Must handle ungraceful disconnects.",
      "alternatives_considered": [
        "HTTP long polling — simpler infrastructure but adds 1-3 seconds of latency per notification cycle, eating into the 15-second window",
        "Server-Sent Events (SSE) — server-to-client only; would still need a separate HTTP endpoint for acceptance, adding complexity",
        "Push notifications (APNs/FCM) — too slow (1-5 seconds delivery) and unreliable for a 15-second window"
      ]
    },
    {
      "decision": "Auto-assign to highest-rated courier on timeout (not re-broadcast or cancel)",
      "gains": "Guarantees every order gets assigned — no order left unmatched. Predictable fallback behavior. Highest-rated courier selection rewards reliable couriers.",
      "sacrifices": "Forces an assignment on a courier who didn't actively accept, which could lead to poor service if the courier is actually busy but didn't update status. Mitigated by requiring couriers to be marked on-duty.",
      "alternatives_considered": [
        "Re-broadcast to a wider zone — adds latency (another 15-second window) and risks cascade failure under load",
        "Cancel and refund — unacceptable customer experience for a delivery marketplace",
        "Assign to closest courier — proximity doesn't correlate with reliability; rating is a better signal"
      ]
    },
    {
      "decision": "Zone-based partitioning of WebSocket gateway instances",
      "gains": "Bounded fan-out per gateway instance. Natural horizontal scaling — add gateway instances per zone as courier density grows. Failure isolation — a gateway crash only affects one zone.",
      "sacrifices": "Cross-zone jobs (pickup in zone A, courier in zone B) require multi-zone fan-out coordination. Mitigated by making eligibility zone-aware and allowing a job to target multiple gateway instances.",
      "alternatives_considered": [
        "Single monolithic WebSocket server — simpler but single point of failure and doesn't scale past ~50K connections",
        "Consistent-hash-based partitioning by courierId — more even distribution but loses the locality benefit of zone-based grouping"
      ]
    }
  ],

  "flexibility_points": [
    {
      "area": "Bid window duration",
      "evolution_path": "The 15-second timeout is a configuration value in the BidWindow aggregate, not a hardcoded constant. Can evolve to dynamic timeouts based on zone density, time of day, or order urgency without architectural changes."
    },
    {
      "area": "Courier scoring and auto-assignment strategy",
      "evolution_path": "Currently highest-rated courier wins auto-assignment. The strategy is a pluggable function: can evolve to factor in proximity, acceptance rate, current workload, or a composite score. Encapsulated behind a CourierRankingStrategy interface."
    },
    {
      "area": "Bidding model (first-accept vs competitive bidding)",
      "evolution_path": "Current model is first-to-accept wins. The atomic claim mechanism can evolve to collect all bids during the window and select the best one, by changing the Lua script from SET-if-not-exists to ZADD (collecting bids in a sorted set) and adding a selection step at timeout. The WebSocket and lifecycle infrastructure remains unchanged."
    },
    {
      "area": "Notification channels",
      "evolution_path": "WebSocket is the primary channel. The fan-out interface is abstracted — can add push notification fallback for couriers with unstable connections without modifying the Bid Window Manager."
    },
    {
      "area": "Eligibility criteria",
      "evolution_path": "Currently zone + vehicle type. The Courier Eligibility Service can incorporate new dimensions (certifications, customer preferences, courier blacklists) by extending its query model. Bidding context is insulated via the EligibleCourierSet value object."
    }
  ],

  "rigidity_points": [
    {
      "area": "Exactly-once assignment invariant",
      "reason": "The atomic Redis Lua script for bid claiming MUST remain the single source of truth for who won a bid. Any bypass or dual-write pattern would violate the core business invariant. This is intentional rigidity — the most critical invariant in the system."
    },
    {
      "area": "Redis as bid state store",
      "reason": "The entire real-time bidding path depends on Redis's single-threaded atomicity guarantees. Swapping Redis for another store requires re-validating the atomicity model. This coupling is acceptable because the bid state is ephemeral (15s TTL) and Redis is operationally well-understood."
    },
    {
      "area": "WebSocket as real-time transport",
      "reason": "The 15-second window demands sub-second notification latency. Any transport change must meet this SLA. WebSocket is deeply integrated into the Courier Gateway. Changing it would require rebuilding the gateway layer."
    },
    {
      "area": "Bid window state machine transitions",
      "reason": "OPEN → CLAIMED and OPEN → EXPIRED are the only valid transitions. Adding intermediate states (e.g., PENDING_CONFIRMATION) would require changes to the Lua script, timeout scheduler, and gateway notification logic. Intentionally kept minimal."
    }
  ],

  "risks": [
    {
      "risk": "Redis single point of failure — if Redis goes down, all active bid windows are lost and no new bids can be processed",
      "severity": "critical",
      "mitigation": "Deploy Redis in Sentinel or Cluster mode with automatic failover. Bid state is ephemeral (15s) so a failover window of 1-2 seconds loses at most a handful of in-flight bids. Add a circuit breaker that queues orders for rebidding if Redis is unavailable."
    },
    {
      "risk": "WebSocket disconnection during bid window — courier loses connection and misses the job, or accepts but the ACK is lost",
      "severity": "high",
      "mitigation": "Implement client-side reconnection with exponential backoff. On reconnect, the courier app queries for any active bid windows it's eligible for. For acceptance ACK loss: the Bid Processor returns the result synchronously, and if the WebSocket drops mid-response, the courier app retries the acceptance call (idempotent since Redis Lua script returns the same result on re-execution)."
    },
    {
      "risk": "Clock skew between Timeout Scheduler instances causes premature or late expiry of bid windows",
      "severity": "medium",
      "mitigation": "Use Redis server time (TIME command) for all timestamp calculations, not local system clocks. The sorted set scores are set by the Bid Window Manager using Redis server time + 15 seconds."
    },
    {
      "risk": "Courier marked on-duty but actually unavailable — auto-assignment forces a job on a courier who can't fulfill it",
      "severity": "high",
      "mitigation": "After auto-assignment, give the assigned courier 60 seconds to confirm. If they don't confirm, re-enter the bidding cycle. Track no-response rates and auto-flag couriers with high no-response for status verification."
    },
    {
      "risk": "Hot zone — a popular pickup zone generates many simultaneous bid windows, all targeting the same 30 couriers",
      "severity": "medium",
      "mitigation": "Rate-limit bid window creation per zone. If more than N bid windows are active for the same zone, queue excess orders with a short backoff. Also implement courier capacity tracking — once a courier has an active bid window they've accepted, exclude them from new windows."
    },
    {
      "risk": "Thundering herd on bid window expiry — if many bid windows expire simultaneously, the Timeout Scheduler and auto-assignment path could spike",
      "severity": "low",
      "mitigation": "ZPOPMIN with a batch size limit (e.g., 10 at a time) rate-limits expiry processing. Multiple Timeout Scheduler instances compete atomically for expired windows, spreading load."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Implement in three phases. Phase 1 (core path): Redis Lua script for atomic bid claiming, Bid Window Manager lifecycle, and basic HTTP-based acceptance endpoint — prove the atomicity invariant works. Phase 2 (real-time): Add WebSocket gateway with zone partitioning, replace HTTP acceptance with WebSocket-based acceptance, add fan-out notifications. Phase 3 (resilience): Add Timeout Scheduler with sorted-set polling, Redis Sentinel failover, reconnection handling, circuit breakers, and monitoring dashboards for bid window metrics (acceptance rate, timeout rate, average time-to-accept).",
    "files_to_create_or_modify": [
